// Fixture for lexer/parser divergence on non-identifier export names.
//
// The character-level lexer (`@endo/cjs-module-analyzer`, the `default` CJS
// parser) emits export names verbatim, including strings that are not valid
// JavaScript identifiers. The Babel analyzer (`CjsModuleSource`, the `babel`
// CJS parser) filters these via `isValidExportName`, because they cannot be
// used as static ESM export bindings.
//
// This module is fully executable: every value is defined, so the divergence
// is purely in *analysis* (which export names are detected), not execution.
const value = 'ok';

module.exports = {
  valid: value,
  'not identifier': value,
  '@notidentifier': value,
};

// Named-property assignment forms (post object-literal) exercise the
// `exports[...] =` detection path as well.
exports['also invalid'] = value;
Object.defineProperty(exports, '%notidentifier', {
  enumerable: true,
  value,
});
